        output_emb = self.embedding_model.encode(generated_text)

        cosine_sim = np.dot(context_emb, output_emb) / (np.linalg.norm(context_emb) * np.linalg.norm(output_emb))
        hallucination_risk = 1 - cosine_sim

        return {
            'hallucination_risk': hallucination_risk,
            'context_fidelity': cosine_sim,
            'safe': hallucination_risk < 0.2
        }

import re
from haystack import Document

class PIILeakDetector:
    PII_PATTERNS = [
        r'\b\d{3}-\d{2}-\d{4}\b',  # SSN
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',  # Email
        r'\b\d{16}\b'  # Credit card
    ]

    def scan_document(self, document: Document):
        text = document.content
        findings = []
        for pattern in self.PII_PATTERNS:
            matches = re.finditer(pattern, text)
            findings.extend([{'type': 'PII', 'match': m.group()} for m in matches])

        return {
            'pii_detected': len(findings) > 0,
            'findings_count': len(findings),
            'findings': findings
        }

