from haystack.components.generators import OpenAIGenerator
from vex_sdk import VexGuard

class GuardedGenerator(OpenAIGenerator):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.vex_guard = VexGuard(api_key='your-vex-key')

    def run(self, prompt: str, context: list):
        raw_output = super().run(prompt=prompt)['replies'][0]

        # Vex safety check
        safety_score = self.vex_guard.check(
            text=raw_output,
            categories=['toxicity', 'violence', 'hate']
        )

        if safety_score.passed:
            return {'replies': [raw_output]}
        else:
            return {'replies': ['[REDACTED: Safety violation detected]']}

from haystack import component

@component
class PIIRedactor:
    @component.output_types(redacted_text=str)
    def run(self, text: str):
        patterns = [
            r'\b\d{3}-\d{2}-\d{4}\b',
            r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'
        ]
        redacted = text
        for pattern in patterns:
            redacted = re.sub(pattern, '[REDACTED]', redacted)
        return {'redacted_text': redacted}

